import Project from "@/types/Project";

export default async function Home() {
  async function fetchProjects() {
    const response = await fetch(
      "https://api-portifolio-production.up.railway.app/projects"
    );

    const data = await response.json();

    return data;
  }
  const { data: projectsData, token } = await fetchProjects();

  return (
    <main className="bg-slate-800 h-screen">
      {projectsData &&
        projectsData.map((project: Project) => (
          <div className="text-white p-8" key={project.id}>
            <h2>{project.projectName}</h2>
            <p>{project.slug}</p>
            <p>{project.description}</p>
            <a href={project.projectLink} target="_blank">
              Ver projeto.
            </a>
            <br />
            <a href={project.githubLink} target="_blank">
              Ver no github
            </a>
          </div>
        ))}

      {token && (
        <div className="text-white p-8">
          <h2>Token de autenticação:</h2>
          <p>{token}</p>
        </div>
      )}
    </main>
  );
}
